import json

with open('baseline-packages-live.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build lookup: project_name -> framework -> package -> version
def build_lookup(data):
    lookup = {}
    for p in data['projects']:
        name = p['path'].split('/')[-1]
        lookup[name] = {}
        for fw in p['frameworks']:
            lookup[name][fw['framework']] = {}
            for pkg in fw['topLevelPackages']:
                lookup[name][fw['framework']][pkg['id']] = pkg['resolvedVersion']
    return lookup

b = build_lookup(baseline)
a = build_lookup(after)

changes = []
unchanged = []

for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    for fw in sorted(set(list(b.get(proj,{}).keys()) + list(a.get(proj,{}).keys()))):
        b_pkgs = b.get(proj,{}).get(fw,{})
        a_pkgs = a.get(proj,{}).get(fw,{})
        all_pkgs = sorted(set(list(b_pkgs.keys()) + list(a_pkgs.keys())))
        for pkg in all_pkgs:
            bv = b_pkgs.get(pkg)
            av = a_pkgs.get(pkg)
            label = f'{proj} ({fw})'
            if bv != av:
                changes.append((label, pkg, bv or 'N/A', av or 'N/A', 'Aligned to highest version'))
            else:
                unchanged.append((label, pkg, av))

if changes:
    print('CHANGES:')
