print()
print('UNCHANGED:')
print(f'{\"Project\":<30} {\"Package\":<50} {\"Version\":<12}')
print('-' * 95)
for u in unchanged:
    print(f'{u[0]:<30} {u[1]:<50} {u[2]:<12}')
"

